class Solution:
  def is_valid_branch(self, branch: str) -> bool:
    # Regular expression to match the branch name pattern
    pattern = re.compile(r'^[a-zA-Z0-9][a-zA-Z0-9.-]*$')
    # Check if the branch name matches the reserved GIT names
    reserved_names = ['HEAD', 'ORIG_HEAD', 'MERGE_HEAD', 'CHERRY_PICK_HEAD']
    if branch in reserved_names:
      return False
    # Check if the branch name matches the regular expression
    return bool(pattern.match(branch))
